import { Route, routes } from './router';

export const homeRoute: Route = {
  path: '/',
  title: 'Acme Dashboard Home',
  body: 'Welcome to Acme',
};

export const pricingRoute: Route = {
  path: '/pricing',
  title: 'Plans &amp; Pricing',
  body: 'Starter: $9/mo',
};

export const aboutRoute: Route = {
  path: '/about',
  title: 'About Acme',
  body: 'Founded 2019',
};

export const statsRoute: Route = {
  path: '/stats',
  title: 'Usage Statistics',
  body: 'Daily Active Users',
};

export const allRoutes: Route[] = [homeRoute, pricingRoute, aboutRoute, statsRoute];

/** One page of the site. */
export interface PageSpec {
  title: string;
  body: string;
}

/**
 * Return the page for a hash route path ("/", "/pricing", ...), or null for
 * unknown routes.
 */
export function routeFor(path: string): PageSpec | null {
  const routes: Record<string, PageSpec> = {
    "/": { title: "Acme Dashboard Home", body: "Welcome to Acme" },
    "/pricing": { title: "Plans & Pricing", body: "Starter: $9/mo" },
    "/about": { title: "About Acme", body: "Founded 2019" },
    "/stats": { title: "Usage Statistics", body: "Daily Active Users" },
  };
  return routes[path] ?? null;
}

/** Raw stats as served by the backend fixture (public/stats.json). */
export interface RawStats {
  dau: number;
  p95_ms: number;
  uptime_pct: number;
}

/** View model rendered on the /stats page. */
export interface StatsView {
  dailyActive: number;
  latencyP95: string;
  uptime: string;
}

/** Map raw stats to the view model for rendering. */
export function formatStats(raw: RawStats): StatsView {
  return {
    dailyActive: raw.dau,
    latencyP95: `${raw.p95_ms} ms`,
    uptime: `${raw.uptime_pct}%`,
  };
}

